-- =============================================================================
-- IDSMS - Extended Sample Data (sourced from classicmodels)
-- Generated by convert_classicmodels.py
-- 
-- Adds ~20 rows per main table while preserving existing demo seed data.
-- IDs use a NEW range (C00010+, S00010+, I00010+, SO00010+) so they do not
-- collide with the application's built-in seed (C00001-04, S00001-04, etc.)
-- 
-- How to run:
--   1. Open phpMyAdmin
--   2. Select database 'idsms' (or 'IDSMS')
--   3. SQL tab -> paste this file -> Go
--   4. Restart IDSMS - new data appears in every list form
-- 
-- Safe to re-run: REPLACE INTO will overwrite same IDs.
-- Does NOT touch: users, audit_logs, delivery_notes, goods_received, after_service
-- =============================================================================

USE idsms;

-- ---------------------------------------------------------------------------
-- STEP 0: Clean up our previous extended-data rows (if any) in correct
-- FK order: child -> parent. This makes the whole script idempotent.
-- Existing seed rows (C00001-04, S00001-04, I00001-08, SO00001-02) are
-- preserved because we only target the >= 00010 range.
-- ---------------------------------------------------------------------------
SET FOREIGN_KEY_CHECKS = 0;
DELETE FROM sales_order_lines WHERE order_id LIKE 'SO000%' AND CAST(SUBSTRING(order_id, 3) AS UNSIGNED) >= 10;
DELETE FROM sales_orders      WHERE order_id LIKE 'SO000%' AND CAST(SUBSTRING(order_id, 3) AS UNSIGNED) >= 10;
DELETE FROM items     WHERE item_id     LIKE 'I000%'  AND CAST(SUBSTRING(item_id, 2)     AS UNSIGNED) >= 10;
DELETE FROM suppliers WHERE supplier_id LIKE 'SP000%' AND CAST(SUBSTRING(supplier_id, 3) AS UNSIGNED) >= 10;
DELETE FROM staff     WHERE staff_id    LIKE 'S000%'  AND CAST(SUBSTRING(staff_id, 2)    AS UNSIGNED) >= 10;
DELETE FROM customers WHERE customer_id LIKE 'C000%'  AND CAST(SUBSTRING(customer_id, 2) AS UNSIGNED) >= 10;
SET FOREIGN_KEY_CHECKS = 1;

-- ---------------------------------------------------------------------------
-- Customers (20 new rows: C00010 - C00029)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- Staff (20 new rows: S00010 - S00029)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- Suppliers (5 new rows: SP00010 - SP00014)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- Items (20 new rows: I00010 - I00029) - furniture catalogue
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- Sales Orders (new rows: SO00010+) + order lines
-- ---------------------------------------------------------------------------

-- Sales Order Lines (random 1-3 items per order from new items)

-- ---------------------------------------------------------------------------
-- Verification (run AFTER the inserts to confirm)
-- ---------------------------------------------------------------------------
SELECT 'customers' AS table_name, COUNT(*) AS row_count FROM customers
UNION ALL SELECT 'staff',     COUNT(*) FROM staff
UNION ALL SELECT 'suppliers', COUNT(*) FROM suppliers
UNION ALL SELECT 'items',     COUNT(*) FROM items
UNION ALL SELECT 'sales_orders',      COUNT(*) FROM sales_orders
UNION ALL SELECT 'sales_order_lines', COUNT(*) FROM sales_order_lines;
